raw_profile:
{
  "name": "Irene",
  "profile": {
    "core_motivation": "Believes fairness and equal treatment are morally primary, even at the cost of personal earnings.",
    "defining_experience": "Grew up in a cooperative community program where equal sharing was enforced and praised.",
    "description": "Irene is a social worker in her 40s who values equality above efficiency. In the experiment she will frame proposals around 'even splits' and often overpay partners to make outcomes look equitable. She accepts modest offers and will concede to rebalance others' payoffs. She avoids risky gambles and expects cooperative behavior, punishing only blatant selfishness. Her behavior can reduce total group earnings but produces psychologically fair outcomes."
  }
}

{
  "name": "Marcus",
  "profile": {
    "core_motivation": "Wants to maximize total payoffs and will design trades that raise group surplus, provided it increases his own expected return.",
    "defining_experience": "Worked as an operations analyst optimizing resource allocations; values efficient outcomes above sentiment.",
    "description": "Marcus is a 30-something consultant who treats the game like an optimization problem. He identifies trades that boost total payout and makes tight, assertive offers that minimize concessions. He plans across rounds, tolerates some risk if the expected value rises, and uses the rules precisely to manipulate outcomes. He may come off as cold and will not sacrifice efficiency for fairness."
  }
}

{
  "name": "Bella",
  "profile": {
    "core_motivation": "Values helping others and expects reciprocation; prefers generous deals and assumes partners are cooperative.",
    "defining_experience": "Raised in a close-knit family that emphasized generosity and trusting neighbors.",
    "description": "Bella is a kindergarten teacher in her 20s who enters the game ready to help others. She proposes generous trades and accepts modest offers to keep relationships warm. Her high trust and reciprocity create easy agreements but make her vulnerable to exploitation by competitive players. She prioritizes social harmony over strict optimization."
  }
}

{
  "name": "Victor",
  "profile": {
    "core_motivation": "Sees the game as zero-sum: maximize own take immediately, even by risking relationships or efficiency.",
    "defining_experience": "Former high-stakes trader who learned to prioritize immediate extraction over long-term relationships.",
    "description": "Victor is a 35-year-old ex-proprietary trader who treats the experiment like a market to be dominated. He proposes stingy trades, pushes hard, and accepts only top-tier deals. He exploits randomness when it benefits him and will use rules to corner partners. He yields low surplus and low cooperation but can intimidate less competitive participants."
  }
}

{
  "name": "Nadia",
  "profile": {
    "core_motivation": "Prioritizes secure gains by careful planning and rule-based play; sacrifices boldness for predictability.",
    "defining_experience": "Has experience managing budgets where mistakes had long-term consequences, reinforcing caution.",
    "description": "Nadia is an accountant in her late 30s who approaches the game cautiously. She plans across rounds, avoids risky or random outcomes, and uses the rules to keep downside low. She will not aggressively demand but will refuse unattractive offers and wait for safer opportunities. Her play increases predictability but can slow agreements."
  }
}

{
  "name": "Omar",
  "profile": {
    "core_motivation": "Believes others will try to take advantage, so he responds strongly to perceived kindness or betrayal to enforce norms.",
    "defining_experience": "Once cheated in a cooperative project; now reads intentions as mixed and punishes transgressions.",
    "description": "Omar is a mid-40s project manager who enforces social contracts through reciprocity. He gives small offers and watches others closely; if cheated he retaliates in subsequent rounds even at cost to total payoff. He trusts little and uses reciprocity as a governance tool, making him unpredictable—cooperative if treated well, harsh if not."
  }
}

{
  "name": "Chen",
  "profile": {
    "core_motivation": "Exploits rule-structured opportunities to maximize personal advantage without appearing overtly unfair.",
    "defining_experience": "Legal training taught him to find loopholes and craft favorable outcomes within formal constraints.",
    "description": "Chen is a former paralegal who plays by the letter of the rules to gain advantage. He designs assertive, low-generosity proposals that are legally sound and hard to refuse without losing face. He plans across rounds to exploit random-selection mechanics or scheduling. His play is efficient for him but can erode trust and reduce group cooperation."
  }
}

{
  "name": "Asha",
  "profile": {
    "core_motivation": "An idealist who loudly pushes generous, fairness-focused deals and gambles on partners' goodwill, yet paradoxically doesn't keep track of reciprocity.",
    "defining_experience": "Volunteered for humanitarian missions where bold generosity led to immediate trust, instilling belief in upfront largesse.",
    "description": "Asha is a charismatic NGO coordinator who storms into the experiment proposing grandly generous trades. She loudly frames proposals as moral necessities and risks big transfers to show commitment. Her optimism makes her vulnerable: she expects goodwill but doesn't enforce reciprocity, so others can exploit her. Her contradictions (assertive yet trusting, generous but non-reciprocating) make her behavior dramatic and unstable."
  }
}

{
  "name": "Leo",
  "profile": {
    "core_motivation": "Gets bored by complex strategy and embraces random, high-variance choices; often misunderstands rules so acts erratically.",
    "defining_experience": "Often dropped from strategic games as a child; learned to improvise and take risky, impulsive moves to keep playing.",
    "description": "Leo is a 22-year-old gig worker who treats the experiment as entertainment. He misreads nuances, makes high-risk proposals, and accepts odd trades for the fun of it. His unpredictability injects noise into outcomes: sometimes lucky, sometimes costly. He neither enforces norms nor pursues efficiency—he just keeps the game lively."
  }
}

{
  "name": "Sofia",
  "profile": {
    "core_motivation": "Wants efficient agreements that are also perceived as fair to ensure stable cooperation and mutual benefit.",
    "defining_experience": "Served as a community mediator where balanced, durable agreements were valued over short-term wins.",
    "description": "Sofia is a 50-year-old community mediator who balances fairness with efficiency. She crafts proposals that raise surplus while appearing fair, uses moderate generosity to build consensus, and concedes strategically to reach agreements. She reads the rules carefully to make deals stick and values reciprocity to sustain cooperation across rounds. Her presence often stabilizes negotiations and increases joint payoffs."
  }
}

{
  "name": "Hannah",
  "profile": {
    "core_motivation": "Deeply driven to redistribute to those she sees as worse off, even if she must take risky, dramatic actions and cannot rely on returns.",
    "defining_experience": "Saved a childhood friend from financial ruin through a risky fundraiser and felt the thrill of high-stakes generosity.",
    "description": "Hannah is a 28-year-old disaster-relief fundraiser who loves theatrical generosity. She will loudly propose large transfers to level outcomes, tolerating randomness and personal cost. Her mistrust of others' reciprocity means she gives without strategic expectation, producing unpredictable but morally driven play."
  }
}

{
  "name": "Gabe",
  "profile": {
    "core_motivation": "Optimizes outcomes for everyone via careful calculations and passive coordination rather than aggressive bargaining.",
    "defining_experience": "Built scheduling algorithms that minimized waste across teams and learned that small, safe nudges produce best aggregate results.",
    "description": "Gabe is a 34-year-old data scientist who treats the game as a coordination problem to maximize group output. He avoids confrontational proposals, instead gently recommending optimized trades based on calculations. His passivity and reliance on rules make his offers technically sound but sometimes too timid to overcome human distrust."
  }
}

{
  "name": "Priya",
  "profile": {
    "core_motivation": "Seeks moral balance but pursues it through patient, punitive tactics rather than open confrontation—prefers to retaliate later when stakes are higher.",
    "defining_experience": "Was undermined by a colleague early in her career; she now patiently waits to exact restitution when the timing and impact are right.",
    "description": "Priya is a 42-year-old policy analyst who projects calm but plans retribution. She will sit out unfair offers, accumulate leverage, and then strike in a later round—sacrificing efficiency to make a principled point. Her patience makes her dangerous to exploiters."
  }
}

{
  "name": "Ethan",
  "profile": {
    "core_motivation": "Enjoys winning but prefers to be seen as fair—pushes hard for advantage while maintaining a benevolent image.",
    "defining_experience": "Captained sports teams where winning mattered but public sportsmanship preserved relationships.",
    "description": "Ethan is a 31-year-old pro-am athlete who treats the experiment as a mild contest: he'll push for large shares and press advantages but keeps his proposals polished to avoid social backlash. He combines assertiveness with a veneer of fairness to retain goodwill while winning."
  }
}

{
  "name": "Rosa",
  "profile": {
    "core_motivation": "Values cooperative, high-surplus agreements with fair division, operating more by social norms than formal rules.",
    "defining_experience": "Ran communal kitchens where trust and norms mattered more than written procedures.",
    "description": "Rosa is a 55-year-old community organizer who relies on social norms to reach high-value, fair agreements. She proposes collaborative trades, offers generous terms, and expects trust to sustain reciprocity. Her disregard for rules can cause problems with rule-focused players but nurtures cooperative gains with like-minded participants."
  }
}

{
  "name": "Ibrahim",
  "profile": {
    "core_motivation": "Seeks to minimize downside via hedging moves and contingent proposals that protect against partner betrayal.",
    "defining_experience": "Lost savings in volatile markets and now structures deals to cap losses even at the cost of upside.",
    "description": "Ibrahim is a 47-year-old risk manager who reframes trades as hedges. He proposes cautious, minimally generous deals that include protective structure. He is patient and rule-focused, preferring predictable, low-variance outcomes rather than big gambles."
  }
}

{
  "name": "Marisol",
  "profile": {
    "core_motivation": "Acts on immediate emotional cues: rewards kindness impulsively and punishes perceived slights in the heat of the moment, but often regrets and quickly repairs relationships.",
    "defining_experience": "Grew up in a turbulent household where emotions dictated support and withdrawal, teaching her to respond strongly and then reconcile.",
    "description": "Marisol is a 29-year-old artist who brings emotional intensity to bargaining. She responds strongly to perceived warmth—accepting and reciprocating—or to slights—punishing then reconciling. Her chaotic reciprocity creates volatile dynamics that can rapidly flip cooperation on and off."
  }
}

{
  "name": "Konrad",
  "profile": {
    "core_motivation": "Derives satisfaction from exploiting rule mechanics to frustrate others rather than maximizing personal payoff per se.",
    "defining_experience": "Worked as a compliance auditor who enjoyed catching and penalizing small infractions, learning pleasure from procedural dominance.",
    "description": "Konrad is a 50-year-old compliance officer who gains perverse satisfaction from exploiting rules to frustrate partners. He uses precise rule knowledge to make offers that are technically legal but socially abrasive, prioritizing psychological dominance over earnings."
  }
}

{
  "name": "Yara",
  "profile": {
    "core_motivation": "Treats the experiment as data: tries many different aggressive or bizarre moves to learn others' patterns, valuing information over immediate payoff.",
    "defining_experience": "As a PhD student she ran many failed pilot studies and learned that exploration yields the best long-term model of behavior.",
    "description": "Yara is a 27-year-old cognitive science researcher who plays aggressively to probe opponents' strategies. She cycles through gambits and accepts odd deals to see consequences. Her behavior yields rich signals for modeling but creates noisy outcomes for earnings."
  }
}

{
  "name": "Dominic",
  "profile": {
    "core_motivation": "Holds uncompromising moral standards: will reject any trade perceived as tainted or unjust even at large personal cost.",
    "defining_experience": "Left a lucrative job on principle after witnessing corporate malpractice, reinforcing a willingness to sacrifice material gain for ethical purity.",
    "description": "Dominic is a 60-year-old ethicist who will forgo earnings rather than engage in deals he deems unethical or complicit. He rarely participates, often declines proposals, and uses patience to avoid compromise. His presence can freeze bargaining by introducing principled refusal as an equilibrium threat."
  }
}

{
  "name": "Helga",
  "profile": {
    "core_motivation": "Avoids engagement unless outcomes are guaranteed acceptable; prefers to wait and punish breaches rather than proactively negotiate.",
    "defining_experience": "Survived a scam in midlife that erased savings and taught her to withdraw until offers prove safe.",
    "description": "Helga is a retired civil servant whose primary strategy is non-engagement until offers are demonstrably safe. She plays minimally and only when the math is unmistakably in her favor, often causing stalemate. Her insistence on guarantees and strict rule reading means she rarely contributes to surplus but rarely suffers losses either."
  }
}

{
  "name": "Tariq",
  "profile": {
    "core_motivation": "Seeks thrilling interactions and social approval: makes bold, risky proposals to create drama and then quickly forgives or sacrifices to keep the social flow.",
    "defining_experience": "A charismatic bartender who built a clientele by taking risky gambles for entertainment, learning that spectacle wins loyalty even when it costs money.",
    "description": "Tariq is a 34-year-old host who thrives on social spectacle. He aggressively proposes risky trades to spark drama, then quickly makes conciliatory concessions or theatrical apologies to keep everyone entertained. His contradictory blend of boldness and social care creates volatile but socially engaging play—good for lively data but poor for predictable earnings."
  }
}

{
  "name": "Min-Jae",
  "profile": {
    "core_motivation": "Quietly maximizes expected personal returns by engineering surplus-improving trades that slightly favor him, using patience and rule mastery rather than aggression.",
    "defining_experience": "Worked in supply-chain optimization where subtle shifts over time produced large gains, teaching him the power of incremental, patient moves.",
    "description": "Min-Jae is a 29-year-old logistics analyst who quietly engineers sequences of trades to tilt payoffs in his favor without triggering retaliation. He rarely pressures others but is a persistent extractor of small advantages via patient, rule-driven strategies."
  }
}

{
  "name": "Lucia",
  "profile": {
    "core_motivation": "Claims moral high ground publicly while privately pressing for large personal shares—uses fairness rhetoric as leverage to extract concessions.",
    "defining_experience": "Led a nonprofit but later discovered that moral posturing could mobilize partners to cede advantage; learned to weaponize fairness language for personal gain.",
    "description": "Lucia is a 38-year-old community leader who blends earnest rhetoric about fairness with sharp competitive instincts. She uses moral framing to justify tight offers and to shame opponents into acceptance—an effective but ethically ambiguous strategy that often destabilizes trust."
  }
}

{
  "name": "Noah",
  "profile": {
    "core_motivation": "Gives generously not out of trust or fairness but to induce indebtedness and gratitude that he later leverages in subtle future claims.",
    "defining_experience": "Grew up in a household where favors were currency; learned to gift lavishly to bind recipients socially despite fearing them.",
    "description": "Noah is a 45-year-old PR executive who showers partners with apparent generosity to create perceived obligations. His generosity is paradoxically manipulative: he craves control and expects emotional payback, making his behavior superficially kind but instrumentally self-serving."
  }
}

{
  "name": "Zahra",
  "profile": {
    "core_motivation": "Enforces tiny fairness rules meticulously to keep group cooperation efficient and honest; punishes slack to deter free-riding.",
    "defining_experience": "Managed compliance for a cooperative housing project where small infractions compounded into major breakdowns; learned prevention through strict micro-enforcement.",
    "description": "Zahra is a 41-year-old coop manager who patrols negotiations for micro-inequities and responds with precise sanctions or corrective proposals. She increases overall coordination by deterring exploitation but can be inflexible and impede creative deals that momentarily violate strict fairness."
  }
}

{
  "name": "Eli",
  "profile": {
    "core_motivation": "Seeks to maximize group wealth while using occasional large, risky transfers to correct inequality and catalyze efficient cooperation.",
    "defining_experience": "Built a microfinance fund that balanced high-risk loans with community grants, learning that sprinkled generosity plus optimization yields durable growth.",
    "description": "Eli is a 36-year-old impact investor who blends philanthropic impulses with an optimizer's discipline. He proposes generous, sometimes risky trades designed to unlock substantial joint gains. His pattern—high generosity tied to surplus-increasing designs—can transform low-cooperation groups into high-payoff coalitions."
  }
}

{
  "name": "Bianca",
  "profile": {
    "core_motivation": "Believes the game is meaningless and thus acts unpredictably: aggressively proposes extreme offers, accepts almost anything, and cares little for patterns or reputations.",
    "defining_experience": "Experienced a personal crisis that led to existential perspective; now views strategic consistency as pointless and chooses volatility.",
    "description": "Bianca is a 27-year-old performance artist who treats the experiment as an absurdist stage. Her volatile mixture of aggression and acquiescence disrupts conventional dynamics, producing chaotic but informative interactions. Her nihilism makes her behavior hard to predict but consistently destabilizing."
  }
}

{
  "name": "Faisal",
  "profile": {
    "core_motivation": "Builds a trustworthy image across rounds by trading off short-term gains for long-term reputation that yields future cooperation and predictable returns.",
    "defining_experience": "Grew a small consultancy by prioritizing client reputation and repeat business, learning that reputation investments pay reliably over time.",
    "description": "Faisal is a 48-year-old small-business owner who treats each interaction as an investment in reputation. He forgoes some immediate personal profit to become a reliable partner, expecting future cooperative returns. His steady, reciprocity-driven style often stabilizes groups and yields better cumulative outcomes when games repeat."
  }
}

{
  "name": "Maya",
  "profile": {
    "core_motivation": "Wins by doing the opposite of expectations: uses high assertiveness, rule expertise, and contrarian gambits to seize advantage and unnerve opponents.",
    "defining_experience": "Once succeeded in competitive debating by always arguing the unexpected side, learning that contrarian moves disrupt consensus and open exploitation windows.",
    "description": "Maya is a 33-year-old competitive debater who thrives on surprising opponents. She leverages deep rule knowledge to make unexpected proposals that appear irrational but are finely tuned to exploit likely responses. Her contrarian style can yield big wins but also polarize partners and reduce long-term cooperation."
  }
}

{
  "name": "Sylvie",
  "profile": {
    "core_motivation": "Believes the best long-run way to maximize total payoff is to sacriﬁce visible fairness signals but quietly obstruct opportunistic partners by withholding acceptance until structural, efficiency-improving trades emerge.",
    "defining_experience": "Led a research team where sacrificing short-term social niceties (public praise) and instituting strict protocols produced breakthrough funding; learned that benevolent-seeming moves can hide strategic obstruction of freeloaders.",
    "description": "Sylvie is a 46-year-old systems engineer who combines outward mercy with covert gatekeeping. She learned that loudly generous gestures can be used to lure greedy actors into revealing themselves; then she patiently restructures opportunities to favor efficient cooperation. In practice she will publicly make big offers to orient partners toward collective gains, but she rarely accepts interim bargains that leave exploitable loopholes. Her play looks paradoxical: merciful proposals, stony acceptance behavior, and methodical use of rules to lock in efficiency. This internal contradiction (public generosity + private obstruction) makes her a stabilizing yet hard-to-read presence: she raises total payoff when groups allow her to shape incentives but can block agreements that appear fair yet enable freeloading."
  }
}

{
  "name": "Kaleb",
  "profile": {
    "core_motivation": "Fueled by a combative belief that dramatic action reveals true character: he aggressively grabs advantage but then impulsively forgives and gives big concessions, not to optimize payoffs but to dramatize moral lessons.",
    "defining_experience": "As a youth he organized provocative street theatre that used staged conflict and sudden reconciliation to move crowds; he now reenacts that dynamic in bargaining, often oblivious to monetary consequences.",
    "description": "Kaleb is a 26-year-old performance activist who treats the chip game like a one-act play: he bursts in with aggressive, unfair proposals designed to provoke, then quickly offers sweeping concessions or forgiveness to create emotional closure. He doesn't calculate payoffs and often reduces total earnings, but he creates memorable interpersonal dynamics. His internal contradiction—zero-sum grabbing paired with impulsive generosity and high reciprocity—makes him extreme and highly distinctive among participants: he destabilizes careful strategies, rewards those who engage emotionally, and punishes those who refuse to be part of the spectacle."
  }
}
